#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 100005
typedef struct Edge {
    int u, v, w;
} Edge;
int max_xor_sum = 0;
void dfs(int u, int v, int xor_sum, int *visited, Edge *edges, int n) {
    visited[u] = 1;
    if(v != -1) xor_sum ^= edges[v].w;
    max_xor_sum = (max_xor_sum > xor_sum) ? max_xor_sum : xor_sum;
    for (int i = 0; i < n - 1; i++) {
        if (edges[i].u == u && !visited[edges[i].v]) {
            dfs(edges[i].v, i, xor_sum, visited, edges, n);
        }
        if (edges[i].v == u && !visited[edges[i].u]) {
            dfs(edges[i].u, i, xor_sum, visited, edges, n);
        }
    }
    visited[u] = 0;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Edge *edges = (Edge *)malloc((n - 1) * sizeof(Edge));
        for (int i = 0; i < n - 1; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
        }
        int *visited = (int *)calloc(n + 1, sizeof(int));
        max_xor_sum = 0;
        for (int i = 1; i <= n; i++) {
            dfs(i, -1, 0, visited, edges, n);
        }
        printf("%d\n", max_xor_sum);
        free(edges);
        free(visited);
    }
    return 0;
}

