// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static int max_xor_sum = 0;
    static class Edge {
        int u, v, w;
    }
    public static void dfs(int u, int v, int xor_sum, boolean[] visited, Edge[] edges, int n) {
        visited[u] = true;
        if(v != -1) xor_sum ^= edges[v].w;
        max_xor_sum = Math.max(max_xor_sum, xor_sum);
        for (int i = 0; i < n - 1; i++) {
            if (edges[i].u == u && !visited[edges[i].v]) {
                dfs(edges[i].v, i, xor_sum, visited, edges, n);
            }
            if (edges[i].v == u && !visited[edges[i].u]) {
                dfs(edges[i].u, i, xor_sum, visited, edges, n);
            }
        }
        visited[u] = false;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            Edge[] edges = new Edge[n - 1];
            for (int i = 0; i < n - 1; i++) {
                edges[i] = new Edge();
                edges[i].u = scanner.nextInt();
                edges[i].v = scanner.nextInt();
                edges[i].w = scanner.nextInt();
            }
            boolean[] visited = new boolean[n + 1];
            max_xor_sum = 0;
            for (int i = 1; i <= n; i++) {
                dfs(i, -1, 0, visited, edges, n);
            }
            System.out.println(max_xor_sum);
        }
    }
}

