let input = () => lines[idx++];
let max_xor_sum = 0;
function dfs(u, v, xor_sum, visited, edges, n) {
    max_xor_sum = Math.max(max_xor_sum, xor_sum);
    visited[u] = true;
    for (let i = 0; i < n - 1; i++) {
        if (edges[i][0] == u && !visited[edges[i][1]]) {
            dfs(edges[i][1], i, xor_sum ^ edges[i][2], visited, edges, n);
        }
        if (edges[i][1] == u && !visited[edges[i][0]]) {
            dfs(edges[i][0], i, xor_sum ^ edges[i][2], visited, edges, n);
        }
    }
    visited[u] = false;
}
